from flask import Flask, request, jsonify
import logging
from werkzeug.security import generate_password_hash, check_password_hash
import os

app = Flask(__name__)

# Configure logging
logging.basicConfig(filename='application.log', level=logging.INFO, format='%(asctime)s - %(message)s')

# In-memory user store (for demonstration purposes)
users = {
    "user@example.com": generate_password_hash("securepassword")
}

def log_login_attempt(username, email, ip_address, user_agent, success):
    logging.info(f"Login attempt - Username: {username}, Email: {email}, IP: {ip_address}, User Agent: {user_agent}, Success: {success}")

@app.route('/login', methods=['POST'])
def login():
    data = request.json
    username = data.get('username')
    password = data.get('password')
    email = data.get('email')
    
    ip_address = request.remote_addr
    user_agent = request.headers.get('User-Agent')

    if email in users and check_password_hash(users[email], password):
        log_login_attempt(username, email, ip_address, user_agent, success=True)
        return jsonify({"message": "Login successful"}), 200
    else:
        log_login_attempt(username, email, ip_address, user_agent, success=False)
        return jsonify({"message": "Invalid credentials"}), 401

